import{_ as o,o as a,c as e,a2 as r}from"./chunks/framework.BQ1gajhD.js";const h=JSON.parse('{"title":"交泰殿","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/forbidden-city/jiaotai-dian.md","filePath":"landmarks/forbidden-city/jiaotai-dian.md","lastUpdated":1784720050000}'),n={name:"landmarks/forbidden-city/jiaotai-dian.md"};function l(i,t,s,d,g,u){return a(),e("div",null,[...t[0]||(t[0]=[r('<h1 id="交泰殿" tabindex="-1">交泰殿 <a class="header-anchor" href="#交泰殿" aria-label="Permalink to &quot;交泰殿&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-1591067457498-5013f5afe0cc?w=1200&amp;q=80" alt="交泰殿"></p><blockquote><p>乾清坤宁之间，一方小殿藏着帝国的印玺与时间。这里是皇后的正殿，也是紫禁城的心跳所在。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>交泰殿位于乾清宫与坤宁宫之间，是内廷后三宫的中间一座，形制与外朝的中和殿如出一辙——方形平面、四角攒尖顶，玲珑小巧地嵌在前后两座大殿之间。&quot;交泰&quot;取《周易》泰卦&quot;天地交而万物通&quot;之意：乾为天、坤为地，乾清与坤宁之间这座小殿，正是&quot;天地交泰&quot;的节点。</p><p>交泰殿建成于明嘉靖年间，现存建筑为清嘉庆三年（1798年）重建。它是<strong>皇后的正殿</strong>——皇后生辰（千秋节）在此接受妃嫔、命妇朝贺；大婚时皇后亦在此受册。清代，这里还成为帝国最高权力的信物保管所：<strong>二十五方御用宝玺</strong>珍藏于此。殿内同时陈设着两件计时重器——铜壶滴漏与大自鸣钟，是紫禁城的时间基准。</p><h2 id="建筑与景观" tabindex="-1">建筑与景观 <a class="header-anchor" href="#建筑与景观" aria-label="Permalink to &quot;建筑与景观&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>平面形制</strong></td><td style="text-align:left;">正方形，面阔、进深各三间</td></tr><tr><td style="text-align:left;"><strong>屋顶</strong></td><td style="text-align:left;">单檐四角攒尖顶，鎏金宝顶</td></tr><tr><td style="text-align:left;"><strong>殿内匾额</strong></td><td style="text-align:left;">&quot;无为&quot;（康熙御笔）</td></tr><tr><td style="text-align:left;"><strong>宝玺</strong></td><td style="text-align:left;">清代二十五方御用国宝，贮于殿内匣中</td></tr><tr><td style="text-align:left;"><strong>计时器</strong></td><td style="text-align:left;">铜壶滴漏（嘉庆年间制）、大自鸣钟（乾隆年间造办处制）</td></tr><tr><td style="text-align:left;"><strong>殿内陈设</strong></td><td style="text-align:left;">宝座、屏风、宝玺匣、计时器分列左右</td></tr></tbody></table><p>交泰殿与外朝中和殿同为方形攒尖顶，但功能完全不同：中和殿是大典前的休息室，交泰殿则是皇后的礼仪空间和帝国的&quot;保险库&quot;。殿内正中高悬**&quot;无为&quot;匾额**（康熙御笔），语出《道德经》&quot;无为而无不为&quot;，是帝王对&quot;垂拱而治&quot;理想境界的自况。</p><p>殿内左右分设两件计时器：西侧为<strong>铜壶滴漏</strong>，是中国传统计时法的最后遗存；东侧为<strong>大自鸣钟</strong>，高近6米，是清宫造办处于乾隆年间仿西洋钟法制成，至今仍能报时。一古一今、一中一西，两件计时器并肩而立，恰是紫禁城在时间观念上新旧交替的缩影。</p><p><strong>二十五宝</strong>是清代皇帝行使权力的二十五方御用印玺，乾隆十三年（1748年）厘定，涵盖皇帝发布诏令、册封、祭祀、军事调遣等一切国家权力行为，各有专司，缺一不可。宝玺平日分贮于交泰殿内的二十五个宝匣之中，由专人看守，是帝国权力运转的&quot;钥匙串&quot;。</p><h2 id="历史故事" tabindex="-1">历史故事 <a class="header-anchor" href="#历史故事" aria-label="Permalink to &quot;历史故事&quot;">​</a></h2><h3 id="二十五方宝玺-权力的钥匙串" tabindex="-1">二十五方宝玺：权力的钥匙串 <a class="header-anchor" href="#二十五方宝玺-权力的钥匙串" aria-label="Permalink to &quot;二十五方宝玺：权力的钥匙串&quot;">​</a></h3><p>乾隆帝是一位极重&quot;名分&quot;的皇帝。他梳理前朝御玺，发现数量混乱、用途不清，遂于乾隆十三年钦定<strong>二十五方宝玺</strong>，每一方对应一项具体的国家权力：如&quot;皇帝之宝&quot;用于颁诏、&quot;制诰之宝&quot;用于册封、&quot;皇帝信宝&quot;用于军事调遣……二十五方宝玺涵盖了帝国权力的一切出口，任何一道圣旨必须钤盖对应的宝玺方为有效。这些宝玺就锁在交泰殿的二十五个匣子里——可以想象，谁控制了交泰殿，谁就控制了帝国的公章。辛亥革命后，二十五宝随故宫文物保存至今，是研究清代典制的核心实物。</p><h3 id="铜壶滴漏与自鸣钟-时间的交接" tabindex="-1">铜壶滴漏与自鸣钟：时间的交接 <a class="header-anchor" href="#铜壶滴漏与自鸣钟-时间的交接" aria-label="Permalink to &quot;铜壶滴漏与自鸣钟：时间的交接&quot;">​</a></h3><p>交泰殿内两件计时器的并置意味深长。铜壶滴漏代表中国延续数千年的水钟传统——以壶中水位下降计量时刻，是农业文明&quot;观水知时&quot;的智慧。而旁边那座近6米高的大自鸣钟，则是18世纪清宫造办处学习欧洲机械钟表的产物，整点报时，钟声可传遍后三宫。嘉庆年间，铜壶滴漏已年久失修、计时不准，宫中实际报时改用自鸣钟，但滴漏依然陈设不撤——它不再是工具，而是传统的纪念碑。</p><h2 id="必看亮点" tabindex="-1">必看亮点 <a class="header-anchor" href="#必看亮点" aria-label="Permalink to &quot;必看亮点&quot;">​</a></h2><ul><li><strong>&quot;无为&quot;匾额</strong>：殿内正中康熙御笔，是理解帝王&quot;无为而治&quot;政治理想的点睛之笔。</li><li><strong>二十五宝玺（展陈）</strong>：殿内陈设的宝玺匣，是帝国权力信物的原址展示，全国仅此一处。</li><li><strong>铜壶滴漏与大自鸣钟</strong>：殿内左右并置的中西计时器，是紫禁城最具&quot;时间哲学&quot;的一组陈设。</li><li><strong>攒尖宝顶</strong>：殿顶鎏金宝顶在阳光下熠熠生辉，与中和殿遥相呼应，是内廷天际线上的精巧点缀。</li></ul><h2 id="参观贴士" tabindex="-1">参观贴士 <a class="header-anchor" href="#参观贴士" aria-label="Permalink to &quot;参观贴士&quot;">​</a></h2><ul><li><strong>别错过殿内陈设</strong>：交泰殿体量虽小，殿内陈设密度极高——宝玺匣、滴漏、自鸣钟、宝座屏风一殿俱全，值得在殿门前驻足细看。</li><li><strong>与中和殿对比</strong>：把交泰殿和外朝中和殿对照着看：同为方形攒尖顶，一为&quot;大典休息室&quot;，一为&quot;皇后正殿+国家保险库&quot;，形制相同而功能迥异，是故宫&quot;前朝后寝&quot;设计的精妙体现。</li><li><strong>注意中轴线节奏</strong>：乾清宫（大）→ 交泰殿（小）→ 坤宁宫（大）的&quot;大-小-大&quot;节奏，与外朝三大殿完全对称——这是故宫规划有意为之的空间韵律。</li><li><strong>最佳拍摄</strong>：从乾清宫后回望或坤宁宫前回望，均可拍到交泰殿攒尖顶的完整轮廓。</li></ul><hr><p><strong>📍 位置</strong>：内廷中轴线，乾清宫与坤宁宫之间 <strong>⏱️ 建议游览</strong>：10-15分钟 <strong>🔗 上一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/qianqing-gong.html">乾清宫</a><strong>🔗 下一站</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/kunning-gong.html">坤宁宫</a><strong>🔗 返回</strong>：<a href="/beijing-travel-guide/landmarks/forbidden-city/">故宫博物院概览</a></p>',22)])])}const c=o(n,[["render",l]]);export{h as __pageData,c as default};
